You should override ObtainJSONWebToken view and ObtainJSONWebToken serializer.
And then in your customized ObtainJSONWebToken serializer, add request parameter in the jwt_payload_handler function.

// urls.py
urlpatterns = [
    url(r'^api-token-auth/', custom_obtain_jwt_token),
    url(r'^api-token-refresh/', refresh_jwt_token),
    url(r'^api-token-verify/', verify_jwt_token),
];

//views.py
class CustomObtainJSONWebToken(JSONWebTokenAPIView):
    serializer_class = CustomJSONWebTokenSerializer

//serializers.py
class CustomJSONWebTokenSerializer(Serializer):
    def __init__(self, *args, **kwargs):
        super(CustomJSONWebTokenSerializer, self).__init__(*args, **kwargs)

        self.fields[self.username_field] = serializers.CharField()
        self.fields['password'] = PasswordField(write_only=True)
        print(self.context['request'])
    @property
    def username_field(self):
        return get_username_field()

    def validate(self, attrs):
        credentials = {
            self.username_field: attrs.get(self.username_field),
            'password': attrs.get('password')
        }

        if all(credentials.values()):
            user = authenticate(**credentials)

            if user:
                if not user.is_active:
                    msg = _('User account is disabled.')
                    raise serializers.ValidationError(msg)

                payload = jwt_payload_handler(user, self.context['request'])

                return {
                    'token': jwt_encode_handler(payload),
                    'user': user
                }
            else:
                msg = _('Unable to log in with provided credentials.')
                raise serializers.ValidationError(msg)
        else:
            msg = _('Must include "{username_field}" and "password".')
            msg = msg.format(username_field=self.username_field)
            raise serializers.ValidationError(msg)

//utils.py
def customized_payload_handler(user, request):
    username_field = get_username_field()
    username = get_username(user)
    
    warnings.warn(
        'The following fields will be removed in the future: '
        '`email` and `user_id`. ',
        DeprecationWarning
    )

    payload = {
        'user_id': user.pk,
        'username': username,
        'exp': datetime.utcnow() + api_settings.JWT_EXPIRATION_DELTA
    }
    if hasattr(user, 'email'):
        payload['email'] = user.email
    if isinstance(user.pk, uuid.UUID):
        payload['user_id'] = str(user.pk)

    payload[username_field] = username

    if api_settings.JWT_ALLOW_REFRESH:
        payload['orig_iat'] = timegm(
            datetime.utcnow().utctimetuple()
        )

    if api_settings.JWT_AUDIENCE is not None:
        payload['aud'] = api_settings.JWT_AUDIENCE

    if api_settings.JWT_ISSUER is not None:
        payload['iss'] = api_settings.JWT_ISSUER

    return payload

//settings.py
JWT_AUTH = {
    'JWT_ENCODE_HANDLER':
    'vinna.utils.encode_handler',

    'JWT_DECODE_HANDLER':
    'vinna.utils.decode_handler',

    'JWT_PAYLOAD_HANDLER':
    'vinna.utils.customized_payload_handler',

    'JWT_PAYLOAD_GET_USER_ID_HANDLER':
    'rest_framework_jwt.utils.jwt_get_user_id_from_payload_handler',

    'JWT_RESPONSE_PAYLOAD_HANDLER':
    'rest_framework_jwt.utils.jwt_response_payload_handler',

    'JWT_GET_USER_SECRET_KEY': None,
    'JWT_PUBLIC_KEY': None,
    'JWT_PRIVATE_KEY': None,
    'JWT_ALGORITHM': 'HS256',
    'JWT_VERIFY': True,
    'JWT_VERIFY_EXPIRATION': True,
    'JWT_LEEWAY': 0,
    'JWT_EXPIRATION_DELTA': datetime.timedelta(seconds=300),
    'JWT_AUDIENCE': None,
    'JWT_ISSUER': None,

    'JWT_ALLOW_REFRESH': True,
    'JWT_REFRESH_EXPIRATION_DELTA': datetime.timedelta(days=7),

    'JWT_AUTH_HEADER_PREFIX': 'JWT',
    'JWT_AUTH_COOKIE': None,
}

Using Django 1.11.7 an approach, albeit not great one, for doing this is as follows;

```python
import algoliasearch_django

class PackageAdmin(admin.ModelAdmin):

    class Meta:
        model = Package

    def response_add(self, request, obj: Package, post_url_continue=None):
        # Ensure we update Algolia's index once all many-to-many fields have been updated.
        algoliasearch_django.save_record(obj)

        return super().response_add(request=request, obj=obj, post_url_continue=post_url_continue)

    def response_change(self, request, obj: Package):
        # Ensure we update Algolia's index once all many-to-many fields have been updated.
        algoliasearch_django.save_record(obj)

        return super().response_change(request=request, obj=obj)
```

Note that you should also set `AUTO_INDEXING` to `False` and also set `auto_indexing=False` when registering your `Package` model.

You probably also want to pay special attention to Django's change log or have some good tests that ensure when you upgrade Django this continues to work.

